const query = $('Webhook').first().json.query || {};
const today = new Date().toISOString().split('T')[0];
const year = String(query.year || new Date().getFullYear());
const dateStart = query.date_start || (year + '-01-01');
const rawEnd = query.date_end || (year + '-12-31');
const dateEnd = rawEnd > today ? today : rawEnd;
const monthStart = today.slice(0,8) + '01';
// Historico viene del archivo; en vivo solo el mes actual
const productPages = [1,2,3,4,5].map(p => ({ page:p, pageSize:100, dateStart, dateEnd, monthStart, fetchStart: monthStart }));
return productPages.map(p => ({ json: p }));

// Productos + Clientes de Siigo, CACHEADOS en staticData.
// No dependen del filtro de fechas -> antes se re-descargaban (~6s) en cada cambio de rango.
const setup = $('Setup').first().json;
const token = $('Auth Siigo').first().json.access_token;
const H = { Authorization: 'Bearer ' + token, 'Partner-Id': 'n8nApp' };
const sd = $getWorkflowStaticData('global');
const TTL = 60 * 60 * 1000; // 1 h
// Version del cache: subir este numero invalida mapsCache al cambiar la logica
// (p.ej. al agregar la fusion de categorias). Si no, se sirve un mapa viejo.
const MAPS_V = 5;

let productMap, customerMap;
if (sd.mapsCache && sd.mapsCache.v === MAPS_V && sd.mapsCache.productMap && (Date.now() - sd.mapsCache.ts) < TTL) {
  productMap  = sd.mapsCache.productMap;
  customerMap = sd.mapsCache.customerMap;
} else {
  // Productos (5 páginas x 100)
  productMap = {};
  for (let p = 1; p <= 5; p++) {
    const res = await this.helpers.httpRequest({ method:'GET',
      url:'https://api.siigo.com/v1/products?page=' + p + '&page_size=100', headers:H, json:true });
    for (const it of (res.results || [])) {
      productMap[String(it.code)] = { name: it.name, category: (it.account_group && it.account_group.name) || 'Sin categoria' };
    }
    if (!(res.results || []).length) break;
  }
  // Clientes (paginado segun total_results)
  customerMap = {};
  const first = await this.helpers.httpRequest({ method:'GET',
    url:'https://api.siigo.com/v1/customers?page=1&page_size=1', headers:H, json:true });
  const total = (first.pagination && first.pagination.total_results) || 0;
  const numPages = Math.ceil(total / 100);
  for (let p = 1; p <= numPages; p++) {
    const res = await this.helpers.httpRequest({ method:'GET',
      url:'https://api.siigo.com/v1/customers?page=' + p + '&page_size=100', headers:H, json:true });
    for (const c of (res.results || [])) {
      const digits = String(c.identification || '').replace(/[^0-9]/g, '');
      if (!digits) continue;
      const raw = c.name;
      const name = Array.isArray(raw) ? raw.filter(Boolean).join(' ') : (raw || digits);
      customerMap[digits] = { name: name || digits,
        idType: String((c.id_type && c.id_type.code) || ''),
        personType: String(c.person_type || '') };
    }
  }
  // Categorias propias (tabla productos_categorias en Supabase) pisan al
  // account_group de Siigo. Siigo no distingue p.ej. BOMBONES de CHUNKS.
  // Los productos que no esten en la tabla conservan la categoria de Siigo.
  try {
    const cats = await this.helpers.httpRequest({ method:'GET',
      url: 'https://wavqyesyqqmawjfaztvb.supabase.co/rest/v1/productos_categorias?select=code,categoria',
      headers: { apikey: '<SUPABASE_SERVICE_ROLE>', Authorization: 'Bearer <SUPABASE_SERVICE_ROLE>' }, json: true });
    const mapeados = new Set();  // codigos presentes en productos_categorias
    for (const r of (Array.isArray(cats) ? cats : [])) {
      const k = String(r.code || '').trim();
      if (!k || !r.categoria) continue;
      const cat = String(r.categoria).trim();
      mapeados.add(k);
      if (productMap[k]) productMap[k].category = cat;
      else productMap[k] = { name: k, category: cat };
    }
    // Solo si la tabla respondio: lo que NO este en ella va a 'Sin categoria'.
    // (Si la tabla fallara, el catch deja las categorias de Siigo y no se
    //  borra todo por un error de red.)
    if (mapeados.size > 0) {
      for (const k of Object.keys(productMap)) {
        if (!mapeados.has(k)) productMap[k].category = 'Sin categoría';
      }
    }
  } catch (e) { /* si falla, se quedan las categorias de Siigo */ }

  sd.mapsCache = { v: MAPS_V, ts: Date.now(), productMap, customerMap };
}

return [{ json: { productMap, customerMap, dateStart: setup.dateStart, dateEnd: setup.dateEnd,
  fetchStart: setup.fetchStart, usedHist: setup.usedHist, monthStart: setup.monthStart } }];

const total = $input.first().json.pagination.total_results || 0;
const setup = $('Build Product Map').first().json;
const PAGE_SIZE = 100;
const numPages = Math.ceil(total / PAGE_SIZE);
const pages = [];
for (let i = 1; i <= numPages; i++) {
  pages.push({ json: { page: i, pageSize: PAGE_SIZE, dateStart: setup.dateStart, dateEnd: setup.dateEnd, fetchStart: setup.fetchStart, totalInvoices: total } });
}
return pages.length > 0 ? pages : [{ json: { page: 1, pageSize: PAGE_SIZE, dateStart: setup.dateStart, dateEnd: setup.dateEnd, fetchStart: setup.fetchStart, totalInvoices: 0 } }];

const productMap = $('Build Customer Map').first().json.productMap || {};

const setup      = $('Build Customer Map').first().json;



// ── Separar input: páginas de facturas vs resumen de notas crédito ─

const __allInput = $input.all();

const __ncItem   = __allInput.find(p => p.json._type === 'nc_summary');

const allNCs     = __ncItem ? (__ncItem.json.ncs || []) : [];



// ── Facturas del mes activo (en vivo) ─────────────────────────────

const liveInvoices = [];

for (const p of __allInput) {

  if (p.json._type === 'nc_summary') continue;

  for (const inv of (p.json.results || [])) liveInvoices.push(inv);

}



// ── Facturas históricas (archivo permanente hasta cierre de mes) ──

let histRows = [];

try {

  const ph = $('Parse Hist').first().json;

  histRows = Array.isArray(ph) ? ph : (ph.rows || ph.data || []);

} catch (e) { histRows = []; }



// ── Merge + dedup por id (la versión viva pisa la histórica) ──────

const byId = {};

for (const inv of histRows)     byId[inv.id] = inv;

for (const inv of liveInvoices) byId[inv.id] = inv;

let invoices = Object.values(byId);



// ── Filtro por rango solicitado (fecha de factura) ────────────────

const ds = setup.dateStart, de = setup.dateEnd;

const invoicesFull = invoices.slice(); // set completo (sin filtro de rango) para "primera compra"

invoices = invoices.filter(inv => { const d = String(inv.date || '').slice(0,10); return d >= ds && d <= de; });



const META_ANUAL = 1600000000;

const TODAY = new Date();

const customerMap = setup.customerMap || {};



// NIT colombiano

function isNIT(identification) {

  const raw = String(identification || '').trim();

  if (/\d{8,9}-\d$/.test(raw)) return true;

  const digits = raw.replace(/[^0-9]/g, '');

  if (digits.length !== 9 && digits.length !== 10) return false;

  return /^(800|811|812|813|820|830|832|860|890|891|892|899|900|901|902)/.test(digits);

}

const B2B_OVERRIDE_IDS = new Set(['1007703532']);

function isCompany(inv) {

  const id     = String((inv.customer && inv.customer.identification) || '');

  const digits = id.replace(/[^0-9]/g, '');

  if (B2B_OVERRIDE_IDS.has(digits)) return true;

  const entry = customerMap[digits];

  if (entry && (entry.idType === '31' || entry.personType === 'Company')) return true;

  if (isNIT(id)) return true;

  const name = String((entry && entry.name) || (inv.customer && inv.customer.name) || '').toLowerCase();

  if (/\b(s\.?a\.?s\.?|ltda\.?|s\.?a\b|corp|inc|group|grupo|distribu|comercial|industria|soluciones|servicios|hospitality|retail|inversiones|supertienda|supermercados)\b/i.test(name)) return true;

  return false;

}

// Canal por centro de costo (168=B2C, 166=B2B, 315=Exportación); override empresa en 168 -> B2B

function channelOf(inv) {

  const cc = Number(inv.cost_center);

  if (cc === 315) return 'export';

  if (cc === 166) return 'b2b';

  if (cc === 168) return isCompany(inv) ? 'b2b' : 'b2c';

  return null; // 170 planta / 172 admin / otros: no son venta

}



// Subtotal (sin impuestos) por ítem y por factura: precio × cantidad − descuento

function itemSubtotal(it) {

  const base = Number(it.price || 0) * Number(it.quantity || 1);

  const disc = (it.discount && it.discount.value) ? Number(it.discount.value) : 0;

  return base - disc;

}

// Facturas en moneda extranjera (exportación EUR/USD): convertir a COP con la tasa del documento

function fxOf(doc) { return (doc.currency && doc.currency.exchange_rate) ? Number(doc.currency.exchange_rate) : 1; }

function invSubtotal(inv) { return (inv.items || []).reduce((s, it) => s + itemSubtotal(it), 0) * fxOf(inv); }



function daysSince(d) { if (!d) return 0; return Math.floor((TODAY - new Date(d)) / 86400000); }

function agingBucket(x) { if (x>180) return '>180'; if (x>120) return '>120'; if (x>90) return '>90'; if (x>31) return '>31'; return 'por_vencer'; }



const byCategory = {}, byMonth = {}, byProduct = {}, byCustomer = {};

const expByMonth = {}, expByProduct = {}, expByCustomer = {};

const catMonth = {}, prodMonth = {};   // pivots: categoria/producto x mes

const monthsSet = {};

const carteraFacturas = [];

let totalB2C = 0, totalB2B = 0, totalExport = 0, totalImpuestos = 0;



for (const inv of invoices) {

  const ch = channelOf(inv);

  if (!ch) continue;                       // ignora planta/admin

  const date  = String(inv.date || '');

  const month = date.slice(0, 7);

  const sub   = invSubtotal(inv);          // ← BASE: subtotal sin IVA

  const custId   = String((inv.customer && inv.customer.identification) || inv.id || 'desconocido');

  const __ce     = customerMap[custId.replace(/[^0-9]/g, '')];

  const custName = (__ce && __ce.name) || (inv.customer && inv.customer.name) || custId;



  if (month) monthsSet[month] = 1;



  if (ch === 'export') totalExport += sub;

  else if (ch === 'b2b') totalB2B += sub;

  else totalB2C += sub;



  // Impuestos (informativo)

  const __fx = fxOf(inv);

  for (const it of (inv.items || [])) totalImpuestos += (it.taxes || []).reduce((s,t)=>s+Number(t.value||0),0) * __fx;



  // Cartera (proporcional al subtotal): pendiente_sub = balance * sub/total

  const balance = Number(inv.balance || 0);

  if (balance > 0 && (ch === 'b2b' || ch === 'export')) {

    const tot = Number(inv.total || 0);

    const pendSub = tot > 0 ? balance * (sub / tot) : balance;

    const dias = daysSince(date);

    carteraFacturas.push({

      numero: inv.name || '', fecha: date, cliente: custName, nit: custId, canal: ch,

      total: Math.round(sub), pendiente: Math.round(pendSub),

      diasVencido: dias, bucket: agingBucket(dias)

    });

  }



  // Mensual global

  if (!byMonth[month]) byMonth[month] = { total:0, facturas:0, b2b:0, b2c:0, export:0 };

  byMonth[month].total += sub; byMonth[month].facturas += 1;

  if (ch==='export') byMonth[month].export += sub; else if (ch==='b2b') byMonth[month].b2b += sub; else byMonth[month].b2c += sub;



  // Cliente global

  if (!byCustomer[custId]) byCustomer[custId] = { identification:custId, name:custName, canal:ch, totalCompras:0, facturas:0, ultimaCompra:'', primeraCompra:'' };

  byCustomer[custId].totalCompras += sub; byCustomer[custId].facturas += 1;

  if (!byCustomer[custId].ultimaCompra  || date > byCustomer[custId].ultimaCompra)  byCustomer[custId].ultimaCompra  = date;

  if (!byCustomer[custId].primeraCompra || date < byCustomer[custId].primeraCompra) byCustomer[custId].primeraCompra = date;



  // Productos / categorías (global) + exportación aparte

  for (const it of (inv.items || [])) {

    const code = String(it.code || '');

    const prod = productMap[code] || { name: it.description || code, category: 'Sin categoria' };

    const s = itemSubtotal(it) * __fx, q = Number(it.quantity || 1);



    if (!byCategory[prod.category]) byCategory[prod.category] = { subtotal:0, qty:0, facturas:0 };

    byCategory[prod.category].subtotal += s; byCategory[prod.category].qty += q; byCategory[prod.category].facturas += 1;



    if (!byProduct[code]) byProduct[code] = { code, name:prod.name, category:prod.category, subtotal:0, qty:0, facturas:0 };

    byProduct[code].subtotal += s; byProduct[code].qty += q; byProduct[code].facturas += 1;



    // Pivots x mes

    if (month) {

      if (!catMonth[prod.category]) catMonth[prod.category] = {};

      if (!catMonth[prod.category][month]) catMonth[prod.category][month] = { subtotal:0, qty:0 };

      catMonth[prod.category][month].subtotal += s; catMonth[prod.category][month].qty += q;

      if (!prodMonth[code]) prodMonth[code] = { code, name:prod.name, category:prod.category, m:{} };

      if (!prodMonth[code].m[month]) prodMonth[code].m[month] = { subtotal:0, qty:0, facturas:0 };

      prodMonth[code].m[month].subtotal += s; prodMonth[code].m[month].qty += q; prodMonth[code].m[month].facturas += 1;

    }



    if (ch === 'export') {

      if (!expByProduct[code]) expByProduct[code] = { code, name:prod.name, category:prod.category, subtotal:0, qty:0, facturas:0 };

      expByProduct[code].subtotal += s; expByProduct[code].qty += q; expByProduct[code].facturas += 1;

    }

  }



  // Exportación: mensual y clientes

  if (ch === 'export') {

    if (!expByMonth[month]) expByMonth[month] = { total:0, facturas:0 };

    expByMonth[month].total += sub; expByMonth[month].facturas += 1;

    if (!expByCustomer[custId]) expByCustomer[custId] = { identification:custId, name:custName, totalCompras:0, facturas:0, ultimaCompra:'', primeraCompra:'' };

    expByCustomer[custId].totalCompras += sub; expByCustomer[custId].facturas += 1;

    if (!expByCustomer[custId].ultimaCompra  || date > expByCustomer[custId].ultimaCompra)  expByCustomer[custId].ultimaCompra  = date;

    if (!expByCustomer[custId].primeraCompra || date < expByCustomer[custId].primeraCompra) expByCustomer[custId].primeraCompra = date;

  }

}



// ── Netear Notas Crédito del período (totales, meses, productos, pivots) ──

const ncsInRange = allNCs.filter(nc => {

  const d = String(nc.date || '').slice(0,10);

  return d >= ds && d <= de;

});

for (const nc of ncsInRange) {

  const ch = channelOf(nc);

  if (!ch) continue;

  const ncFx  = fxOf(nc);

  const ncSub = (nc.items || []).reduce((s, it) => s + itemSubtotal(it), 0) * ncFx;

  if (ch === 'export') totalExport -= ncSub;

  else if (ch === 'b2b') totalB2B -= ncSub;

  else totalB2C -= ncSub;



  const month = String(nc.date || '').slice(0, 7);

  if (byMonth[month]) {

    byMonth[month].total -= ncSub;

    if (ch === 'export') byMonth[month].export -= ncSub;

    else if (ch === 'b2b') byMonth[month].b2b -= ncSub;

    else byMonth[month].b2c -= ncSub;

  }



  // Restar por producto / categoría / pivots (igual que el reporte de Siigo)

  for (const it of (nc.items || [])) {

    const code = String(it.code || '');

    const prod = productMap[code] || { name: it.description || code, category: 'Sin categoria' };

    const s = itemSubtotal(it) * ncFx, q = Number(it.quantity || 1);

    if (byCategory[prod.category]) { byCategory[prod.category].subtotal -= s; byCategory[prod.category].qty -= q; }

    if (byProduct[code]) { byProduct[code].subtotal -= s; byProduct[code].qty -= q; }

    if (month && catMonth[prod.category] && catMonth[prod.category][month]) {

      catMonth[prod.category][month].subtotal -= s; catMonth[prod.category][month].qty -= q;

    }

    if (month && prodMonth[code] && prodMonth[code].m[month]) {

      prodMonth[code].m[month].subtotal -= s; prodMonth[code].m[month].qty -= q;

    }

    if (ch === 'export' && expByProduct[code]) { expByProduct[code].subtotal -= s; expByProduct[code].qty -= q; }

  }



  // Restar del cliente y de exportación mensual

  const ncCed = String((nc.customer && nc.customer.identification) || '');

  if (ncCed && byCustomer[ncCed]) byCustomer[ncCed].totalCompras -= ncSub;

  if (ch === 'export') {

    if (expByMonth[month]) expByMonth[month].total -= ncSub;

    if (ncCed && expByCustomer[ncCed]) expByCustomer[ncCed].totalCompras -= ncSub;

  }

}



// ── Compras Destacadas (solo B2C, insumo para campañas) ──────────

const GEN_IDS = new Set(['222222222222', '7777777777777']);

const esModDest = nm => /^(sel\s|no aplica)/i.test(nm);

const b2cInvs = invoices.filter(inv => channelOf(inv) === 'b2c');



// Cross-sell: se descartan las parejas que incluyan bombones, su propio estuche

// (Caja bom pre, 304) o los chocolates CH / CH DE MESA. Son cruces triviales

// (los bombones se venden surtidos DENTRO de esa caja; los CH son el chocolate

// que va DENTRO de la bebida) y tapaban los cruces realmente accionables.

// Solo afecta a 'parejas'; estos productos siguen contando en el resto.

// Ojo: /^CH(\s|$)/ y no startsWith('CH'), para no arrastrar CHUNKS.

const CROSS_SKIP_CODES = new Set(['304']);

const fueraDeCrossSell = (code, cat) =>

  CROSS_SKIP_CODES.has(String(code)) ||

  String(cat || '').toUpperCase() === 'BOMBONES' ||

  /^CH(\s|$)/i.test(String(cat || ''));



const dProdMes = {}, dProdCli = {}, dPares = {}, dCust = {};

for (const inv of b2cInvs) {

  const fx  = fxOf(inv);

  const mes = String(inv.date || '').slice(0, 7);

  const dia = String(inv.date || '').slice(0, 10);

  const cedRaw = String((inv.customer && inv.customer.identification) || '').replace(/[^0-9]/g, '');

  const ced = (cedRaw && !GEN_IDS.has(cedRaw)) ? cedRaw : null;

  const ceD = ced ? customerMap[ced] : null;

  const cliName = (ceD && ceD.name) || ced || '';

  const nombresFactura = new Set();

  for (const it of (inv.items || [])) {

    const s = itemSubtotal(it) * fx;

    if (s <= 0) continue;

    const prodD = productMap[String(it.code || '')] || { name: it.description || it.code };

    if (esModDest(prodD.name)) continue;

    const q = Number(it.quantity || 1);

    const codeK = String(it.code || prodD.name);

    if (!dProdMes[codeK]) dProdMes[codeK] = { code: codeK, name: prodD.name, total: 0, meses: {} };

    dProdMes[codeK].total += s;

    if (!dProdMes[codeK].meses[mes]) dProdMes[codeK].meses[mes] = { qty: 0, subtotal: 0 };

    dProdMes[codeK].meses[mes].qty += q; dProdMes[codeK].meses[mes].subtotal += s;

    if (ced) {

      if (!dProdCli[codeK]) dProdCli[codeK] = {};

      if (!dProdCli[codeK][ced]) dProdCli[codeK][ced] = { ced, name: cliName, qty: 0, subtotal: 0 };

      dProdCli[codeK][ced].qty += q; dProdCli[codeK][ced].subtotal += s;

    }

    if (!fueraDeCrossSell(codeK, prodD.category)) nombresFactura.add(prodD.name);

  }

  const arrN = [...nombresFactura].sort();

  for (let i = 0; i < arrN.length; i++)

    for (let j = i + 1; j < arrN.length; j++) {

      const k = arrN[i] + '|||' + arrN[j];

      dPares[k] = (dPares[k] || 0) + 1;

    }

  if (ced) {

    if (!dCust[ced]) dCust[ced] = { ced, name: cliName, total: 0, compras: 0, ultima: '' };

    dCust[ced].total += invSubtotal(inv); dCust[ced].compras += 1;

    if (dia > dCust[ced].ultima) dCust[ced].ultima = dia;

  }

}

const dTop = Object.values(dProdMes).sort((a, b) => b.total - a.total);

const dst_productosPorMes = dTop.slice(0, 8).map(p => ({

  code: p.code, name: p.name, total: Math.round(p.total),

  series: Object.entries(p.meses).sort((a, b) => a[0].localeCompare(b[0]))

    .map(e => ({ mes: e[0], qty: Math.round(e[1].qty * 100) / 100, subtotal: Math.round(e[1].subtotal) }))

}));

const dst_clientesPorProducto = dTop.slice(0, 30).map(p => ({

  code: p.code, name: p.name, total: Math.round(p.total),

  clientes: Object.values(dProdCli[p.code] || {}).sort((a, b) => b.subtotal - a.subtotal).slice(0, 10)

    .map(c => ({ name: c.name, ced: c.ced, qty: Math.round(c.qty * 100) / 100, subtotal: Math.round(c.subtotal) }))

}));

const dst_parejas = Object.entries(dPares).sort((a, b) => b[1] - a[1]).slice(0, 15)

  .map(e => { const p = e[0].split('|||'); return { a: p[0], b: p[1], veces: e[1] }; });

const dst_reactivar = Object.values(dCust)

  .filter(c => c.ultima && (TODAY - new Date(c.ultima)) / 86400000 > 60)

  .sort((a, b) => b.total - a.total).slice(0, 30)

  .map(c => ({ name: c.name, ced: c.ced, total: Math.round(c.total), compras: c.compras,

    ultima: c.ultima, diasSin: Math.floor((TODAY - new Date(c.ultima)) / 86400000) }));

const dPrimera = {};

for (const inv of invoicesFull) {

  const cf = String((inv.customer && inv.customer.identification) || '').replace(/[^0-9]/g, '');

  if (!cf || GEN_IDS.has(cf)) continue;

  const df = String(inv.date || '').slice(0, 10);

  if (!dPrimera[cf] || df < dPrimera[cf]) dPrimera[cf] = df;

}

const dNR = {}, dVistos = {};

for (const inv of b2cInvs) {

  const cf = String((inv.customer && inv.customer.identification) || '').replace(/[^0-9]/g, '');

  if (!cf || GEN_IDS.has(cf)) continue;

  const mesNR = String(inv.date || '').slice(0, 7);

  if (!dVistos[mesNR]) dVistos[mesNR] = {};

  if (dVistos[mesNR][cf]) continue;

  dVistos[mesNR][cf] = true;

  if (!dNR[mesNR]) dNR[mesNR] = { nuevos: 0, recurrentes: 0 };

  if (String(dPrimera[cf] || '').slice(0, 7) === mesNR) dNR[mesNR].nuevos++;

  else dNR[mesNR].recurrentes++;

}

const dst_nuevosRecurrentes = Object.entries(dNR).sort((a, b) => a[0].localeCompare(b[0]))

  .map(e => ({ mes: e[0], nuevos: e[1].nuevos, recurrentes: e[1].recurrentes }));



const totalGeneral = totalB2C + totalB2B + totalExport;



const categorias = Object.entries(byCategory).map(([cat,v]) => ({ categoria:cat, subtotal:Math.round(v.subtotal), qty:v.qty, facturas:v.facturas })).sort((a,b)=>b.subtotal-a.subtotal);

