const SB='https://wavqyesyqqmawjfaztvb.supabase.co';
const KEY='<SUPABASE_SERVICE_ROLE>';
const H={ apikey:KEY, Authorization:'Bearer '+KEY };

// Mismo cálculo de rango que el nodo Setup (este nodo corre antes que él)
const q = $('Webhook').first().json.query || {};
const today = new Date().toISOString().split('T')[0];
const year = String(q.year || new Date().getFullYear());
const dateStart = q.date_start || (year + '-01-01');
const rawEnd = q.date_end || (year + '-12-31');
const dateEnd = rawEnd > today ? today : rawEnd;

// 1) Facturas del rango (payload completo)
const rows = [];
{
  const step = 1000; let from = 0;
  const url = SB + '/rest/v1/ventas_invoices?select=raw&fecha=gte.' + dateStart + '&fecha=lte.' + dateEnd + '&order=id.asc';
  while (true) {
    const res = await this.helpers.httpRequest({ method:'GET', url,
      headers:{ ...H, 'Range-Unit':'items', 'Range': from + '-' + (from + step - 1) }, json:true });
    const arr = Array.isArray(res) ? res : [];
    for (const r of arr) { if (r && r.raw) rows.push(r.raw); }
    if (arr.length < step) break;
    from += step; if (from > 100000) break;
  }
}

// 2) Primera compra por cédula: cacheada en staticData (no depende del rango pedido).
//    Solo cambia cuando entran facturas nuevas a Supabase (cierre mensual / backfill).
const sd = $getWorkflowStaticData('global');
const PRIMERAS_TTL = 6 * 60 * 60 * 1000; // 6 h
let primeras = null;
if (sd.primerasCache && sd.primerasCache.map && (Date.now() - sd.primerasCache.ts) < PRIMERAS_TTL) {
  primeras = sd.primerasCache.map;
} else {
  primeras = {};
  const step = 1000; let from = 0;
  const url = SB + '/rest/v1/ventas_invoices?select=ident:raw->customer->>identification,fecha&order=fecha.asc';
  while (true) {
    const res = await this.helpers.httpRequest({ method:'GET', url,
      headers:{ ...H, 'Range-Unit':'items', 'Range': from + '-' + (from + step - 1) }, json:true });
    const arr = Array.isArray(res) ? res : [];
    for (const r of arr) {
      const cf = String((r && r.ident) || '').replace(/[^0-9]/g, '');
      const df = String((r && r.fecha) || '').slice(0, 10);
      if (!cf || !df) continue;
      if (!primeras[cf] || df < primeras[cf]) primeras[cf] = df;
    }
    if (arr.length < step) break;
    from += step; if (from > 100000) break;
  }
  sd.primerasCache = { ts: Date.now(), map: primeras };
}

return [{ json: { rows, count: rows.length, primeras, dateStart, dateEnd } }];

